      SEO.JSONLD.HowToStep.build(%{name: "Bake", text: "Bake at 375F for 10-12 minutes."})
    ],
    nutrition:
      SEO.JSONLD.NutritionInformation.build(%{
        calories: "180 calories",
        serving_size: "1 cookie"
      })
  })
  ```

